sparql:
SELECT ?duration WHERE {
  ?song wdtp:P2047 ?duration .
  ?song wdt:P658 wd:Q6347879 .
  ?song rdfs:label 'Dilruba' @en
}

SELECT ?earthquake(str(?magnitude) AS ?magnitude) WHERE {
  ?earthquake wdt:P2527 ?magnitude .
  ?earthquake wdt:P625 wd:Q13261374 .
}
ORDER BY DESC(?magnitude)
LIMIT 1

SELECT ?person WHERE {
  ?person wdt:P166 wd:Q106291 .
  ?person wdt:P161 wd:Q201674
}

SELECT ?movie ?releaseDate WHERE {
  ?movie wdt:P577 ?releaseDate .
  FILTER(STRSTARTS(STR(?movie) , 'War for the Planet of the Apes'))
}

SELECT ?crop WHERE {
  wd:Q30 wdt:P10960 ?crop .
  ?crop wdt:P31 wd:Q235352 .
}

SELECT ?episode ?episodeLabel ?releaseDate WHERE {
  wd:Q5383538 wdt:P577 ?releaseDate .
  ?episode rdfs:label ?episodeLabel .
  FILTER(LANG(?episodeLabel) = 'en')
}

SELECT DISTINCT ?s WHERE {
  ?s wdt:P585 ?date .
  ?s wdt:P276 wd:Q16
}

SELECT ?nation WHERE {
  ?nation wdt:P31 wd:Q1346016 ; wdte:P706 wd:Q1247 .
}

SELECT ?houseControl ?senateControl WHERE {
  ?houseControl wdt:P102 wd:Q29552 .
  ?senateControl wdt:P102 wd:Q29468 .
}

SELECT ?country(STR(?country) AS ?name)(STR(?area) AS ?area) WHERE {
  ?country wdt:P2046 ?area .
}
ORDER BY DESC(?area)
LIMIT 1

SELECT ?series(COUNT(?season) AS ?numSeasons) WHERE {
  ?series wdt:P2437 ?numSeasons .
}
GROUP BY ?series

SELECT ?game ?releaseDate WHERE {
  ?game wdt:P577 ?releaseDate .
  FILTER(STRSTARTS(STR(?game) , "Star Wars Battlefront II") || STRSTARTS(STR(?game) , "Battlefront II"))
}

SELECT ?city(STR(?population) AS ?population) WHERE {
  ?city wdt:P1082 ?population .
}
ORDER BY DESC(?population)
LIMIT 3

SELECT ?actor WHERE {
  ?actor wdt:P453 wd:Q2635122 .
  ?actor wdt:P161 wd:Q82729 .
}

SELECT ?nextSenateElection WHERE {
  ?nextSenateElection rdfs:label ?label .
  FILTER(CONTAINS(STR(?label) , 'Senate election') || CONTAINS(STR(?label) , 'federal election'))
}

SELECT ?song ?lyricist WHERE {
  ?song wdt:P676 ?lyricist .
  ?song rdfs:label "Always Be Humble and Kind" @en
}

SELECT ?powerPlant(MAX(?capacity) AS ?maxCapacity) WHERE {
  ?powerPlant wdt:P2109 ?capacity .
}
GROUP BY ?powerPlant

SELECT ?weapon WHERE {
  VALUES ?weapon {
    wd:Q124443940 wd:Q482529 wd:Q292668 wd:Q907351 wd:Q482511 wd:Q1143777 wd:Q1062668 wd:Q1058450
  }
}

SELECT ?city ?continent WHERE {
  ?city wdt:P131 ?location .
  ?location wdt:P30 ?continent .
  FILTER(?continent != wd:Q30235317 && ?continent != wd:Q30239975)
}

SELECT ?station WHERE {
  ?station rdfs:label "space station" @en .
  FILTER(lang(?station) = 'en')
}
LIMIT 10

SELECT ?telescope(IF(EXISTS {
  ?telescope wdt:P730 ?retirementDate
}
, "terminated" , "in service") AS ?status) WHERE {
  VALUES ?telescope {
    wd:Q2513 wd:Q186447 wd:Q47272 wd:Q201953 wd:Q7998593
  }
}

SELECT ?zone(rdfs:label AS ?label) WHERE {
  VALUES ?zone {
    wd:Q5477586 wd:Q55968502 wd:Q58533016
  }
}

SELECT DISTINCT ?upperStage(rdfs:label AS ?label) WHERE {
  ?upperStage rdfs:label ?label .
  FILTER(CONTAINS(STR(?label) , "upper stage"))
}

SELECT ?author WHERE {
  ?novel wdt:P144 ?movie .
  ?novel wdt:P1082 ?author .
  ?movie rdfs:label "The Lord of the Rings" @en .
  ?novel rdfs:label "The Lord of the Rings" @en
}

SELECT DISTINCT ?voiceActor WHERE {
  wd:Q98537283 wdt:P725 ?voiceActor .
  ?voiceActor wdt:P31 wd:Q13110753
}

SELECT(COUNT(?film) AS ?count) WHERE {
  ?film wdt:P571 ?releaseYear .
  ?film wdt:P1810 ?series .
  ?series wdtd:P571 wd:Q2716420 .
  FILTER(?releaseYear < '2013-01-01' ^^ xsd:date)
}

SELECT ?book ?publicationYear WHERE {
  ?book wdt:P577 ?publicationYear .
  FILTER(CONTAINS(str(?book) , 'The Clan of the Cave Bear'))
}

SELECT ?year WHERE {
  wd:Q631 wdt:P2522 wd:Q153585 .
  ?year wdty:yearNumber wd:Q153585
}

SELECT ?character ?relation WHERE {
  ?character wdtp:P1441 wd:Q184222 .
  ?character wdtp:P1441 wd:Q36097 .
}

SELECT ?wife ?father(STR(?title) AS ?title) WHERE {
  ?wife wdt:P26 wd:Q38370 .
  ?wife wdt:P22 ?father .
  ?father rdfs:label ?title .
}

SELECT ?tailor WHERE {
  ?tailor wdt:P31 wd:Q472717 .
  ?tailor wdt:P571 ?date .
  ?date datatypeweb:year ?year .
  FILTER(?year >= 1901 && ?year <= 2000)
}

SELECT ?caliphate ?caliph ?occupation WHERE {
  ?caliph wdt:P106 ?occupation .
  ?caliph rdfs:label ?caliph_label .
  ?caliph rdfs:label ?caliph_label .
  FILTER(CONTAINS(STR(?caliph_label) , 'first caliph') || CONTAINS(STR(?caliph_label) , 'Abu Bakr') || CONTAINS(STR(?caliph_label) , 'Muawiya I') || CONTAINS(STR(?caliph_label) , 'Abu al-Abbas as-Saffah') || CONTAINS(STR(?caliph_label) , 'Muhammad al-Fatimid'))
}

SELECT ?country ?countryLabel ?parliament ?parliamentLabel ?seats WHERE {
  ?country wdt:P194 ?parliament .
  ?parliament wdt:P1342 ?seats .
  ?country rdfs:label ?countryLabel .
  ?parliament rdfs:label ?parliamentLabel .
}

SELECT DISTINCT ?character (rdfs:label AS ?label)
WHERE {
  ?character wdt:P31 wd:Q4205826 .
}
UNION
SELECT DISTINCT ?character (rdfs:label AS ?label)
WHERE {
  ?character wdt:P31 wd:Q4463198 .
}

SELECT ?player WHERE {
  ?player wdt:P54 wd:Q4574182 .
  ?player wdt:P1050 ?injury .
  ?injury wdwd:P14591 ?kneeSurgery .
  ?injury wdt:P276 wd:Q271880
}

SELECT ?game(MAX(?duration) AS ?maxDuration) WHERE {
  ?game wdt:P2047 ?duration .
  ?game wdt:P1923 wd:Q334634 .
  ?game wdt:P1923 wd:Q650840 .
  ?game wdt:P118 wd:Q865526
}
